import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.util.Log
import java.util.regex.Pattern

class DeepLinkActivity : AppCompatActivity() {

    companion object {
        private const val TAG = "DeepLinkActivity"
        private const val SCHEME = "myapp"
        private const val HOST_PROFILE = "profile"
        private const val HOST_PAYMENT = "payment"
        private const val PATH_CONFIRM = "confirm"
        
        private val PROFILE_ID_PATTERN = Pattern.compile("^[0-9]+$")
        private val ALLOWED_HOSTS = setOf(HOST_PROFILE, HOST_PAYMENT)
        private val ALLOWED_PAYMENT_PATHS = setOf(PATH_CONFIRM)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val uri = intent?.data
        
        if (uri == null) {
            Log.e(TAG, "No URI found in intent")
            handleInvalidDeepLink()
            return
        }
        
        handleDeepLink(uri)
    }

    private fun handleDeepLink(uri: Uri) {
        if (!isValidScheme(uri)) {
            Log.e(TAG, "Invalid scheme: ${uri.scheme}")
            handleInvalidDeepLink()
            return
        }

        val host = uri.host?.lowercase()
        if (host == null || !ALLOWED_HOSTS.contains(host)) {
            Log.e(TAG, "Invalid or missing host: $host")
            handleInvalidDeepLink()
            return
        }

        when (host) {
            HOST_PROFILE -> handleProfileDeepLink(uri)
            HOST_PAYMENT -> handlePaymentDeepLink(uri)
            else -> handleInvalidDeepLink()
        }
    }

    private fun isValidScheme(uri: Uri): Boolean {
        return uri.scheme?.lowercase() == SCHEME
    }

    private fun handleProfileDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            Log.e(TAG, "Profile deep link missing path segments")
            handleInvalidDeepLink()
            return
        }

        val profileId = pathSegments[0]
        
        if (!isValidProfileId(profileId)) {
            Log.e(TAG, "Invalid profile ID: $profileId")
            handleInvalidDeepLink()
            return
        }

        navigateToProfile(profileId)
    }

    private fun isValidProfileId(profileId: String): Boolean {
        if (profileId.length > 20) {
            return false
        }
        return PROFILE_ID_PATTERN.matcher(profileId).matches()
    }

    private fun handlePaymentDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            Log.e(TAG, "Payment deep link missing path segments")
            handleInvalidDeepLink()
            return
        }

        val action = pathSegments[0].lowercase()
        
        if (!ALLOWED_PAYMENT_PATHS.contains(action)) {
            Log.e(TAG, "Invalid payment action: $action")
            handleInvalidDeepLink()
            return
        }

        when (action) {
            PATH_CONFIRM -> navigateToPaymentConfirm(uri)
            else -> handleInvalidDeepLink()
        }
    }

    private fun navigateToProfile(profileId: String) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_PROFILE_ID, profileId)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun navigateToPaymentConfirm(uri: Uri) {
        val queryParams = extractSafeQueryParams(uri)
        
        val intent = Intent(this, PaymentConfirmActivity::class.java).apply {
            putExtra(PaymentConfirmActivity.EXTRA_QUERY_PARAMS, queryParams)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun extractSafeQueryParams(uri: Uri): Bundle {
        val bundle = Bundle()
        val allowedParams = setOf("transaction_id", "amount", "currency", "status")
        
        uri.queryParameterNames.forEach { paramName ->
            if (allowedParams.contains(paramName.lowercase())) {
                val value = uri.getQueryParameter(paramName)
                if (value != null && isSafeQueryValue(value)) {
                    bundle.putString(paramName, value)
                }
            }
        }
        
        return bundle
    }

    private fun isSafeQueryValue(value: String): Boolean {
        if (value.length > 500) {
            return false
        }
        
        val dangerousPatterns = listOf(
            "<script",
            "javascript:",
            "onerror=",
            "onclick=",
            "../",
            "..\\",
            "%00"
        )
        
        val lowerValue = value.lowercase()
        return dangerousPatterns.none { lowerValue.contains(it) }
    }

    private fun handleInvalidDeepLink() {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }
}

